/// Executor for UserSuspension flow
pub struct UserSuspensionFlowExecutor<H: UserSuspensionStepHandler>(FlowExecutor<H>);

impl<H: UserSuspensionStepHandler + Send + Sync + 'static> UserSuspensionFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self(FlowExecutor::new(handler))
    }

    /// Start a new flow instance
    pub fn start(&self, instance_id: impl Into<String>) -> UserSuspensionFlowInstance {
        self.0.start(instance_id, UserSuspensionFlowStep::GetUser)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut UserSuspensionFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            UserSuspensionFlowStep::GetUser => {
                self.0.handler.handle_get_user(instance).await?
            }
            UserSuspensionFlowStep::ValidateNotAdmin => {
                let next = self.0.handler.evaluate_validate_not_admin(instance).await?;
                Some(next)
            }
            UserSuspensionFlowStep::TerminateSessions => {
                self.0.handler.handle_terminate_sessions(instance).await?
            }
            UserSuspensionFlowStep::SuspendUser => {
                self.0.handler.handle_suspend_user(instance).await?
            }
            UserSuspensionFlowStep::RecordSuspension => {
                self.0.handler.handle_record_suspension(instance).await?
            }
            UserSuspensionFlowStep::SendSuspensionEmail => {
                self.0.handler.handle_send_suspension_email(instance).await?
            }
            UserSuspensionFlowStep::CheckDuration => {
                let next = self.0.handler.evaluate_check_duration(instance).await?;
                Some(next)
            }
            UserSuspensionFlowStep::ScheduleUnsuspension => {
                self.0.handler.handle_schedule_unsuspension(instance).await?
            }
            UserSuspensionFlowStep::AutoUnsuspend => {
                self.0.handler.handle_auto_unsuspend(instance).await?
            }
            UserSuspensionFlowStep::WaitForManualAction => {
                self.0.handler.handle_wait_for_manual_action(instance).await?
            }
            UserSuspensionFlowStep::HandleUnsuspension => {
                let next = self.0.handler.evaluate_handle_unsuspension(instance).await?;
                Some(next)
            }
            UserSuspensionFlowStep::ProcessAppeal => {
                self.0.handler.handle_process_appeal(instance).await?
            }
            UserSuspensionFlowStep::ManualUnsuspend => {
                self.0.handler.handle_manual_unsuspend(instance).await?
            }
            UserSuspensionFlowStep::SendUnsuspensionEmail => {
                self.0.handler.handle_send_unsuspension_email(instance).await?
            }
            UserSuspensionFlowStep::LogUnsuspension => {
                self.0.handler.handle_log_unsuspension(instance).await?
            }
            UserSuspensionFlowStep::Complete => {
                self.0.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            UserSuspensionFlowStep::ErrorCannotSuspendAdmin => {
                self.0.handler.handle_error_cannot_suspend_admin(instance).await?
            }
            UserSuspensionFlowStep::ErrorEnd => {
                self.0.handler.handle_error_end(instance).await?;
                None // Terminal step
            }
            UserSuspensionFlowStep::ArchiveSuspension => {
                self.0.handler.handle_archive_suspension(instance).await?
            }
            UserSuspensionFlowStep::ArchivedEnd => {
                self.0.handler.handle_archived_end(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = FlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut UserSuspensionFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != FlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut UserSuspensionFlowInstance) { self.0.cancel(instance) }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut UserSuspensionFlowInstance, error: impl Into<String>) { self.0.fail(instance, error) }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = UserSuspensionFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, FlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = UserSuspensionFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = UserSuspensionFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = FlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = FlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
